import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { useNavigate, Link } from 'react-router-dom';
import { LogIn, Mail, Lock, Loader2 } from 'lucide-react';

const Login = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      // AJUSTA ESTA URL A TU BACKEND REAL (ej: http://localhost:5000/api/login)
      const response = await fetch('http://localhost:5000/api/auth/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ 
          correo: email, // Usamos 'correo' como en tu Mongo
          password: password 
        })
      });

      const data = await response.json();

      if (response.ok) {
        // data debe traer el objeto con el campo 'rol'
        login(data); 
        navigate('/');
      } else {
        setError(data.message || 'Credenciales incorrectas');
      }
    } catch (err) {
      setError('Error al conectar con el servidor.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={pageWrapper}>
      <div style={overlay}>
        <div style={loginCard}>
          <div style={headerStyle}>
            <div style={iconCircle}><LogIn size={28} color="#e67e22" /></div>
            <h2 style={titleStyle}>¡Bienvenido!</h2>
          </div>

          {error && <div style={errorBadge}>{error}</div>}

          <form onSubmit={handleSubmit} style={formStyle}>
            <div style={inputGroup}>
              <label style={labelStyle}>Email</label>
              <div style={inputWrapper}>
                <Mail size={18} color="#94a3b8" style={inputIcon} />
                <input
                  type="email"
                  style={inputStyle}
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  required
                />
              </div>
            </div>

            <div style={inputGroup}>
              <label style={labelStyle}>Contraseña</label>
              <div style={inputWrapper}>
                <Lock size={18} color="#94a3b8" style={inputIcon} />
                <input
                  type="password"
                  style={inputStyle}
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  required
                />
              </div>
            </div>

            <button type="submit" style={btnSubmit} disabled={loading}>
              {loading ? <Loader2 size={20} className="spinner" /> : 'Iniciar Sesión'}
            </button>
          </form>

          <div style={footerStyle}>
            ¿No tienes cuenta? <Link to="/registro" style={linkStyle}>Regístrate</Link>
          </div>
        </div>
      </div>
      <style>{`.spinner { animation: spin 1s linear infinite; } @keyframes spin { to { transform: rotate(360deg); } }`}</style>
    </div>
  );
};

const pageWrapper = { width: '100%', height: '100vh', background: '#0f172a' };
const overlay = { display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100%' };
const loginCard = { background: 'white', padding: '40px', borderRadius: '24px', width: '100%', maxWidth: '400px' };
const headerStyle = { marginBottom: '20px', textAlign: 'center' };
const iconCircle = { width: '50px', height: '50px', background: '#fff7ed', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 10px' };
const titleStyle = { color: '#1e293b', fontSize: '1.4rem' };
const formStyle = { textAlign: 'left' };
const inputGroup = { marginBottom: '15px' };
const labelStyle = { display: 'block', marginBottom: '5px', fontSize: '0.8rem', fontWeight: 'bold' };
const inputWrapper = { position: 'relative', display: 'flex', alignItems: 'center' };
const inputIcon = { position: 'absolute', left: '15px' };
const inputStyle = { width: '100%', padding: '10px 10px 10px 40px', borderRadius: '10px', border: '1px solid #e2e8f0' };
const btnSubmit = { width: '100%', padding: '12px', background: '#e67e22', color: 'white', border: 'none', borderRadius: '10px', cursor: 'pointer', fontWeight: 'bold' };
const errorBadge = { background: '#fee2e2', color: '#dc2626', padding: '10px', borderRadius: '10px', marginBottom: '15px', fontSize: '0.8rem' };
const footerStyle = { marginTop: '20px', textAlign: 'center', fontSize: '0.85rem' };
const linkStyle = { color: '#e67e22', fontWeight: 'bold', textDecoration: 'none' };

export default Login;
